// UB budget: 192KB per core (example)
static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN = 64;

static inline uint32_t AlignDown(uint32_t x, uint32_t a) {
    return (x / a) * a;
}

static inline uint32_t CeilDiv(uint32_t a, uint32_t b) {
    return (a + b - 1u) / b;
}

static ge::graphStatus TilingFunc(gert::TilingContext *context) {
    GemmSwishDivideClampTanhClampCustomTilingData tiling;

    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape *w_shape = context->GetInputShape(1);
    uint32_t M = x_shape->GetDim(0);
    uint32_t K = x_shape->GetDim(1);
    uint32_t N = w_shape->GetDim(0);

    // Estimate tile sizes from UB: A(tileM*tileK), B(tileK*tileN), C(tileM*tileN)
    uint32_t tileM = 64;
    uint32_t tileN = 64;
    uint32_t tileK = 64;
    uint32_t needed = (tileM * tileK + tileK * tileN + tileM * tileN) * sizeof(float);
    while (needed > UB_BUDGET_BYTES / 2 && tileM > 32) {
        tileM >>= 1;
        tileN >>= 1;
        tileK >>= 1;
        needed = (tileM * tileK + tileK * tileN + tileM * tileN) * sizeof(float);
    }

    // Align to 64
    tileM = AlignDown(tileM, ALIGN);
    tileN = AlignDown(tileN, ALIGN);
    tileK = AlignDown(tileK, ALIGN);

    uint32_t blockDim = CeilDiv(M, tileM);
    if (blockDim < 8) blockDim = 8;
    if (blockDim > 24) blockDim = 24;

    context->SetBlockDim(blockDim);

    tiling.set_totalM(M);
    tiling.set_totalN(N);
    tiling.set_totalK(K);
    tiling.set_tileM(tileM);
    tiling.set_tileN(tileN);
    tiling.set_tileK(tileK);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

